class Solution:
    def isSubPath(self, head, root) -> bool:
        def match(lst, node):
            if lst is None:
                return True
            if node is None:
                return False
            if lst.val != node.val:
                return False
            return match(lst.next, node.left) or match(lst.next, node.right)
        def dfs(node):
            if node is None:
                return False
            return match(head, node) or dfs(node.left) or dfs(node.right)
        return dfs(root)

