var isSubPath = function(head, root) {
    function match(lst, node) {
        if (!lst) return true;
        if (!node || lst.val !== node.val) return false;
        return match(lst.next, node.left) || match(lst.next, node.right);
    }
    function dfs(node) {
        if (!node) return false;
        if (match(head, node)) return true;
        return dfs(node.left) || dfs(node.right);
    }
    return dfs(root);
};
